SELECT COUNT(*) AS membership_count_expect_23 FROM memberships;
SELECT MIN(id)  AS mem_min_id_expect_1        FROM memberships;
SELECT MAX(id)  AS mem_max_id_expect_23       FROM memberships;

-- Verify no gaps in user IDs
SELECT id, username FROM users ORDER BY id;

-- Verify memberships still correctly link to users
SELECT m.id AS mem_id, m.user_id, u.username, mc.name AS class, m.expires_at
FROM memberships m
JOIN users u ON m.user_id = u.id
JOIN membership_classes mc ON m.membership_class_id = mc.id
ORDER BY m.id;

-- Verify Oshin (founding 00007) is now user_id 7, membership_id 7
SELECT m.id AS mem_id, m.user_id, u.username
FROM memberships m JOIN users u ON m.user_id = u.id
WHERE u.username = 'oshinjangalwa';

